import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useArticle } from '../context/ArticleContext';
import { API_BASE_URL } from '../config';

const Home = () => {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showRegisterModal, setShowRegisterModal] = useState(false);
  const { user } = useAuth();
  const { getArticleStats } = useArticle();
  const [searchParams] = useSearchParams();
  const searchTerm = searchParams.get('search');

  useEffect(() => {
    fetchArticles();
  }, [searchTerm]);

  const fetchArticles = async () => {
    try {
      let url;
      if (searchTerm) {
        url = `${API_BASE_URL}/articles?search=${searchTerm}`;
      } else if (!user) {
        url = `${API_BASE_URL}/articles/homepage`;
      } else {
        url = `${API_BASE_URL}/articles`;
      }

      const res = await fetch(url);
      const data = await res.json();
      setArticles(data);
      setLoading(false);
    } catch (error) {
      console.error('Failed to fetch articles:', error);
      setLoading(false);
    }
  };

  const handleLoadMore = () => {
    if (!user) {
      setShowRegisterModal(true);
    }
  };

  if (loading) return <div style={styles.loading}>加载中...</div>;

  return (
    <div style={styles.container}>
      <div style={styles.grid}>
        {articles.map(article => {
          const isVideo = article.coverImage && /\.(mp4|webm)(\?.*)?$/i.test(article.coverImage);
          const audioUrl = article.audioUrl;
          return article.contentLink ? (
            <a href={article.contentLink} target="_blank" rel="noopener noreferrer" key={article.id} style={styles.card}>
              {isVideo ? (
                <div style={styles.videoWrapper}>
                  <video src={article.coverImage} autoPlay loop playsInline style={styles.video} muted={!audioUrl} />
                  {audioUrl && <audio src={audioUrl} autoPlay loop style={{display: 'none'}} />}
                </div>
              ) : (
                <img src={article.coverImage || '/placeholder.jpg'} alt={article.title} style={styles.image} />
              )}
              <div style={styles.content}>
                <h2 style={styles.title}>{article.title}</h2>
                <div style={styles.meta}>
                  <span>{article.author}</span>
                  <span>{new Date(article.createdAt).toLocaleDateString('zh-CN')}</span>
                </div>
                <p style={styles.excerpt}>{article.excerpt}</p>
                <div style={styles.tags}>
                  {article.tags?.map(tag => (
                    <span key={tag} style={styles.tag}>{tag}</span>
                  ))}
                </div>
                <div style={styles.stats}>
                  <span style={styles.stat}>❤️ {(getArticleStats(article.id).likes ?? article.likes) || 0}</span>
                  <span style={styles.stat}>👁️ {(getArticleStats(article.id).views ?? article.views) || 0}</span>
                </div>
                {article.isPaid && (
                  <span style={styles.paidBadge}>付费</span>
                )}
                <span style={styles.linkBadge}>🔗 外链</span>
              </div>
            </a>
          ) : (
            <Link to={`/article/${article.id}`} key={article.id} style={styles.card}>
            {isVideo ? (
              <div style={styles.videoWrapper}>
                <video src={article.coverImage} autoPlay loop playsInline style={styles.video} muted={!audioUrl} />
                {audioUrl && <audio src={audioUrl} autoPlay loop style={{display: 'none'}} />}
              </div>
            ) : (
              <img src={article.coverImage || '/placeholder.jpg'} alt={article.title} style={styles.image} />
            )}
            <div style={styles.content}>
              <h2 style={styles.title}>{article.title}</h2>
              <div style={styles.meta}>
                <span>{article.author}</span>
                <span>{new Date(article.createdAt).toLocaleDateString('zh-CN')}</span>
              </div>
              <p style={styles.excerpt}>{article.excerpt}</p>
              <div style={styles.tags}>
                {article.tags?.map(tag => (
                  <span key={tag} style={styles.tag}>{tag}</span>
                ))}
              </div>
              <div style={styles.stats}>
                <span style={styles.stat}>❤️ {(getArticleStats(article.id).likes ?? article.likes) || 0}</span>
                <span style={styles.stat}>👁️ {(getArticleStats(article.id).views ?? article.views) || 0}</span>
              </div>
              {article.isPaid && (
                <span style={styles.paidBadge}>付费</span>
              )}
            </div>
          </Link>
          );
        })}
      </div>

      {!user && articles.length >= 3 && (
        <button onClick={handleLoadMore} style={styles.loadMoreBtn}>
          查看更多文章
        </button>
      )}

      {showRegisterModal && (
        <div style={styles.modal} onClick={() => setShowRegisterModal(false)}>
          <div style={styles.modalContent} onClick={e => e.stopPropagation()}>
            <h2>注册后查看更多</h2>
            <p>注册登录后即可浏览全部文章内容</p>
            <Link to="/register" style={styles.modalBtn}>立即注册</Link>
          </div>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '2rem auto',
    padding: '0 1rem',
  },
  loading: {
    textAlign: 'center',
    padding: '4rem',
    fontSize: '1.2rem',
  },
  grid: {
    columnCount: 3,
    columnGap: '2rem',
    '@media (max-width: 1024px)': {
      columnCount: 2,
    },
    '@media (max-width: 640px)': {
      columnCount: 1,
    },
  },
  card: {
    background: '#fff',
    borderRadius: '12px',
    overflow: 'hidden',
    boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
    transition: 'transform 0.2s',
    position: 'relative',
    breakInside: 'avoid',
    marginBottom: '2rem',
    display: 'inline-block',
    width: '100%',
  },
  image: {
    width: '100%',
    height: 'auto',
    display: 'block',
  },
  videoWrapper: {
    position: 'relative',
    width: '100%',
  },
  video: {
    width: '100%',
    height: '200px',
    objectFit: 'cover',
    display: 'block',
